package com.example.demo.controller;

import com.example.demo.model.Product;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.concurrent.ConcurrentHashMap;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private static final Logger logger = LoggerFactory.getLogger(ProductController.class);
    private final ConcurrentHashMap<String, Product> products = new ConcurrentHashMap<>();

    public ProductController() {
        products.put("1", new Product("1", "Laptop", 1200.00));
        products.put("2", new Product("2", "Mouse", 25.00));
        products.put("3", new Product("3", "Keyboard", 75.00));
        logger.info("Initialized {} products in the repository.", products.size());
    }

    @GetMapping
    public ResponseEntity<List<Product>> getAllProducts() {
        logger.info("Received request to get all products.");
        List<Product> productList = new ArrayList<>(products.values());
        logger.info("Successfully retrieved {} products.", productList.size());
        return new ResponseEntity<>(productList, HttpStatus.OK);
    }

    @GetMapping("/{id}")
    public ResponseEntity<Product> getProductById(@PathVariable String id) {
        logger.info("Received request to get product with ID: {}", id);
        Optional<Product> product = Optional.ofNullable(products.get(id));

        if (product.isPresent()) {
            logger.info("Successfully retrieved product: {}", product.get().getName());
            return new ResponseEntity<>(product.get(), HttpStatus.OK);
        } else {
            logger.warn("Product with ID: {} not found.", id);
            return new ResponseEntity<>(HttpStatus.NOT_FOUND);
        }
    }

    @PostMapping
    public ResponseEntity<Product> createProduct(@RequestBody Product product) {
        logger.info("Received request to create product: {}", product.getName());
        if (product.getId() == null || product.getId().isEmpty()) {
            product.setId(String.valueOf(products.size() + 1)); // Simple ID generation
            logger.debug("Generated ID for new product: {}", product.getId());
        }
        products.put(product.getId(), product);
        logger.info("Successfully created product with ID: {}", product.getId());
        return new ResponseEntity<>(product, HttpStatus.CREATED);
    }

    @PutMapping("/{id}")
    public ResponseEntity<Product> updateProduct(@PathVariable String id, @RequestBody Product product) {
        logger.info("Received request to update product with ID: {}", id);
        if (!products.containsKey(id)) {
            logger.warn("Attempted to update non-existent product with ID: {}", id);
            return new ResponseEntity<>(HttpStatus.NOT_FOUND);
        }
        product.setId(id); // Ensure the ID from path is used
        products.put(id, product);
        logger.info("Successfully updated product with ID: {}", id);
        return new ResponseEntity<>(product, HttpStatus.OK);
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteProduct(@PathVariable String id) {
        logger.info("Received request to delete product with ID: {}", id);
        if (products.remove(id) != null) {
            logger.info("Successfully deleted product with ID: {}", id);
            return new ResponseEntity<>(HttpStatus.NO_CONTENT);
        } else {
            logger.warn("Attempted to delete non-existent product with ID: {}", id);
            return new ResponseEntity<>(HttpStatus.NOT_FOUND);
        }
    }
}